[MATH text=g_n'(x)=nx^{n-1}\cos x-x^n \sin x]. 1 p.

&NewLine;

[MATH text=S_0=\int_0^{\pi}\sin x\,dx=2]. 1 p.

&NewLine;

[MATH text=C_0=\int_0^{\pi}\cos x\,dx=0]. 1 p.

&NewLine;

[MATH text=S_4=4C_3+\pi^4=4(-3S_2)+\pi^4] 1 p.

&NewLine;

[MATH text==-12S_2+\pi^4=-12(2C_1+\pi^2)+\pi^4][MATH text==24S_0-12\pi^2+\pi^4=48-12\pi^2+\pi^4\approx 26\mathrm{,}97]. 1 p.

&NewLine;

Funktiota [MATH text=f_n'] integroimalla saadaan [MATH text=\int_0^{\pi}f_n'(x)\, dx=\int_0^{\pi}(nx^{n-1}\sin x+x^n\cos x)\, dx][MATH text==nS_{n-1}+C_{n}]. 1 p.

&NewLine;

Lisäks[MATH text=i \int_0^{\pi}f_n'(x)\, dx=f_n(\pi)-f_n(0)=0]. 1 p.

&NewLine;

Funktiota [MATH text=g_n'] integroimalla saadaan [MATH text=\int_0^{\pi}g_n'(x)\, dx=\int_0^{\pi}(nx^{n-1}\cos x-x^n \sin x)\, dx=nC_{n-1}-S_{n}]. 1 p.

&NewLine;

Lisäksi [MATH text=\int_0^{\pi}g_n'(x)\, dx=g_n(\pi)-g_n(0)=-\pi^n]. 1 p.

&NewLine;

Yhteensä siis [MATH text=nS_{n-1}+C_{n}=0 ja nC_{n-1}-S_{n}=-\pi^n]. 1 p.

&NewLine;

Ensimmäisestä saadaan [MATH text=C_n=-nS_{n-1} ja S_n=nC_{n-1}+\pi^n]. 1 p.

